parameters.query:
SELECT DISTINCT ON (project_name, keyword) project_name, keyword, current_position, search_volume
FROM keyword_rankings
ORDER BY project_name, keyword, recorded_date DESC;

parameters.jsCode:
// If no keywords tracked yet, seed default keywords for all clients
const items = $input.all();
if (items.length === 0 || !items[0].json.keyword) {
  const defaultKeywords = [
    // Aarohaom
    { project_name: 'aarohaom', keyword: 'ayurvedic treatment', search_volume: 2400 },
    { project_name: 'aarohaom', keyword: 'ayurveda wellness', search_volume: 1200 },
    { project_name: 'aarohaom', keyword: 'natural healing ayurveda', search_volume: 880 },
    { project_name: 'aarohaom', keyword: 'panchakarma treatment', search_volume: 1600 },
    // Black Panda
    { project_name: 'blackpanda', keyword: 'India market entry', search_volume: 390 },
    { project_name: 'blackpanda', keyword: 'fractional GCC India', search_volume: 170 },
    { project_name: 'blackpanda', keyword: 'India expansion consulting', search_volume: 260 },
    // Aged Dentistry
    { project_name: 'ageddentistry', keyword: 'dentist near me', search_volume: 60500 },
    { project_name: 'ageddentistry', keyword: 'dental implants', search_volume: 33100 },
    { project_name: 'ageddentistry', keyword: 'teeth whitening', search_volume: 27100 },
    { project_name: 'ageddentistry', keyword: 'emergency dentist', search_volume: 22200 },
  ];
  return defaultKeywords.map(k => ({ json: k }));
}
return items;

const serpData = $input.item.json;
const keyword = $('Handle Empty / Use Defaults').item.json.keyword;
const projectName = $('Handle Empty / Use Defaults').item.json.project_name;
const previousPosition = $('Handle Empty / Use Defaults').item.json.current_position || null;
const searchVolume = $('Handle Empty / Use Defaults').item.json.search_volume || 0;

// Client domain mappings
const domainMap = {
  aarohaom: 'aarohaom.com',
  blackpanda: 'blackpandaenterprises.com',
  ageddentistry: 'ageddentistry.org'
};

const targetDomain = domainMap[projectName] || '';
const organicResults = serpData.organic_results || [];

let currentPosition = null;
let urlRanking = null;
let featuredSnippet = false;

// Check featured snippet
if (serpData.answer_box?.domain === targetDomain) {
  featuredSnippet = true;
  currentPosition = 0;
  urlRanking = serpData.answer_box?.link;
}

// Find domain in organic results
for (let i = 0; i < organicResults.length; i++) {
  const result = organicResults[i];
  if (result.domain === targetDomain || (result.link && result.link.includes(targetDomain))) {
    currentPosition = i + 1;
    urlRanking = result.link;
    break;
  }
}

const positionChange = (previousPosition !== null && currentPosition !== null)
  ? previousPosition - currentPosition  // positive = improved
  : 0;

return [{ json: {
  projectName,
  keyword,
  currentPosition,
  previousPosition,
  positionChange,
  searchVolume,
  urlRanking,
  featuredSnippet,
  needsRedAlert: positionChange <= -3,
  needsGreenAlert: positionChange >= 3,
  recordedDate: new Date().toISOString().split('T')[0]
}}];

// Aggregate all ranking results into a summary
const allItems = $input.all();
const rankings = allItems.map(i => i.json).filter(r => r.projectName);

const improved = rankings.filter(r => r.positionChange >= 3);
const dropped = rankings.filter(r => r.positionChange <= -3);

let msg = `*📊 Weekly Rank Tracker — ${new Date().toDateString()}*\n\n`;

const byProject = {};
rankings.forEach(r => {
  if (!byProject[r.projectName]) byProject[r.projectName] = [];
  byProject[r.projectName].push(r);
});

Object.entries(byProject).forEach(([project, kws]) => {
  msg += `*${project.toUpperCase()}*\n`;
  kws.forEach(kw => {
    if (!kw.keyword) return;
    const pos = kw.currentPosition || 'Not ranked';
    const change = kw.positionChange > 0 ? `+${kw.positionChange} 📈` 
                 : kw.positionChange < 0 ? `${kw.positionChange} 📉` : '→';
    msg += `  • _${kw.keyword}_ — #${pos} (${change})\n`;
  });
  msg += '\n';
});

if (improved.length > 0) {
  msg += `\n🟢 ${improved.length} keyword(s) improved 3+ positions this week`;
}
if (dropped.length > 0) {
  msg += `\n🔴 ${dropped.length} keyword(s) dropped 3+ positions — needs attention`;
}

return [{ json: { summaryText: msg } }];
